                        break;
                    case 'n':
                        string_add('\n');
                        break;
                    case 'r':
                        string_add('\r');
                        break;
                    case 't':
                        string_add('\t');
                        break;
                    case 'u':

                        if (end - i < 4 ||
                            (uc_b1 = hex_value(*++i)) == 0xFF ||
                            (uc_b2 = hex_value(*++i)) == 0xFF
